{"command": "python3 -c "
import csv
from collections import Counter

with open('/root/nexa-paraguay/docs/09-market-intelligence/asuncion-complete-1485-places.csv') as f:
    reader = csv.DictReader(f)
    rows = list(reader)

# Use name-based categorization since primary_type is generic
cats = Counter()
for r in rows:
    n = r.get('name', '').lower()
    if not n: continue
    if any(x in n for x in ['school', 'college', 'colegio', 'academy', 'university', 'instituto', 'liceo']):
        cats['🏫 Schools'] += 1
    elif any(x in n for x in ['hospital', 'clinic', 'clinica', 'sanatorio', 'health']):
        cats['🏥 Hospitals/Clinics'] += 1
    elif any(x in n for x in ['bank', 'banco', 'financiera', 'caja']):
        cats['🏦 Banks'] += 1
    elif any(x in n for x in ['pharmacy', 'farmacia', 'drugstore']):
        cats['💊 Pharmacies'] += 1
    elif any(x in n for x in ['supermarket', 'supermercado', 'stock', 'superseis', 'biggie']):
        cats['🛒 Supermarkets'] += 1
    elif any(x in n for x in ['shopping', 'mall', 'shopping del sol', 'paseo', 'mariscal lopez']):
        cats['🏬 Shopping Centers'] += 1
    elif any(x in n for x in ['restaurant', 'restaurante', 'pizzeria', 'parrilla']):
        cats['🍽️ Restaurants'] += 1
    elif any(x in n for x in ['hotel', 'hostel', 'lodging', 'resort', 'posada']):
        cats['🏨 Hotels'] += 1
    elif any(x in n for x in ['embassy', 'embajada', 'consulate']):
        cats['🏛️ Embassies'] += 1
    elif any(x in n for x in ['church', 'iglesia', 'templo', 'cathedral', 'capilla']):
        cats['⛪ Churches'] += 1
    elif any(x in n for x in ['park', 'parque', 'plaza', 'jardin', 'museum', 'museo']):
        cats['🌳 Parks/Museums'] += 1
    elif any(x in n for x in ['gym', 'gimnasio', 'fitness', 'crossfit']):
        cats['🏋️ Gyms'] += 1
    elif any(x in n for x in ['car rental', 'rent a car', 'alquiler', 'auto']):
        cats['🚗 Car Rental'] += 1
    elif any(x in n for x in ['airport', 'aeropuerto']):
        cats['✈️ Airport'] += 1

total_named = sum(cats.values())
print(f'Identified from names: {total_named} out of {len(rows)} total')
print(f'Unidentified (generic names): {len(rows) - total_named}')
print()
for cat, count in cats.most_common():
    print(f'{count:4d} | {cat}')
